const fs = require("fs");
const path = require("path");

const root = path.resolve(__dirname, "../../..");
const slug = "002_nolan_young_theme_astragrid_systems";
const displayName = "Nolan Young Theme 002 - AstraGrid Systems";
const themeDir = path.join(root, "wp-content/themes", slug);
const previewDir = path.join(root, "docs/themes", slug);

function write(rel, content, base = root) {
  const target = path.join(base, rel);
  fs.mkdirSync(path.dirname(target), { recursive: true });
  fs.writeFileSync(target, content);
}

function wpAsset(file, alt) {
  return `<?php echo esc_url( get_template_directory_uri() . '/assets/images/${file}' ); ?>`;
}

function svg(title, variant) {
  const nodes = Array.from({ length: 11 }, (_, i) => {
    const x = 42 + ((i * 47) % 430);
    const y = 46 + ((i * 67) % 248);
    const r = 5 + (i % 3);
    return `<circle cx="${x}" cy="${y}" r="${r}" fill="${i % 4 === 0 ? "#b8ff4d" : "#38d6ff"}" opacity="${0.55 + (i % 3) * 0.14}"/>`;
  }).join("");
  const panels = Array.from({ length: 4 }, (_, i) => {
    const x = 36 + i * 108;
    const y = 216 - i * 24;
    return `<rect x="${x}" y="${y}" width="82" height="${44 + i * 18}" rx="10" fill="#10243d" stroke="#38d6ff" opacity="0.78"/><path d="M${x + 16} ${y + 18}h42M${x + 16} ${y + 32}h28" stroke="#dff8ff" opacity="0.76"/>`;
  }).join("");
  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 560 360" role="img" aria-labelledby="title desc">
  <title id="title">${title}</title>
  <desc id="desc">Original AstraGrid Systems ${variant} interface artwork.</desc>
  <defs>
    <linearGradient id="bg" x1="0" x2="1" y1="0" y2="1"><stop stop-color="#06111f"/><stop offset="1" stop-color="#0f1d32"/></linearGradient>
    <linearGradient id="glow" x1="0" x2="1"><stop stop-color="#38d6ff"/><stop offset="1" stop-color="#b8ff4d"/></linearGradient>
    <filter id="soft"><feGaussianBlur stdDeviation="12"/></filter>
  </defs>
  <rect width="560" height="360" rx="28" fill="url(#bg)"/>
  <path d="M0 74H560M0 148H560M0 222H560M0 296H560M74 0V360M148 0V360M222 0V360M296 0V360M370 0V360M444 0V360" stroke="#24425f" stroke-width="1" opacity="0.34"/>
  <ellipse cx="430" cy="82" rx="92" ry="38" fill="#38d6ff" opacity="0.14" filter="url(#soft)"/>
  <ellipse cx="158" cy="292" rx="110" ry="44" fill="#b8ff4d" opacity="0.08" filter="url(#soft)"/>
  <path d="M58 272C132 112 236 256 308 128C366 24 458 72 508 34" fill="none" stroke="url(#glow)" stroke-width="4" stroke-linecap="round"/>
  <path d="M86 74h152c24 0 44 20 44 44v58c0 24 20 44 44 44h148" fill="none" stroke="#38d6ff" stroke-width="2" opacity="0.34"/>
  ${variant === "console" ? panels : nodes}
  <rect x="42" y="38" width="202" height="72" rx="16" fill="#081827" stroke="#38d6ff" opacity="0.92"/>
  <path d="M66 66h92M66 86h128" stroke="#dff8ff" stroke-width="7" stroke-linecap="round" opacity="0.72"/>
  <rect x="276" y="250" width="214" height="70" rx="18" fill="#0b1828" stroke="#b8ff4d" opacity="0.88"/>
  <path d="M304 278h122M304 298h74" stroke="#dff8ff" stroke-width="6" stroke-linecap="round" opacity="0.7"/>
</svg>`;
}

